import tensorflow as tf  # Framework de Deep Learning
import keras             # API do TensorFlow
import numpy as np
import matplotlib
from matplotlib import pyplot as plt

# Exibe as versões das bibliotecas para garantir compatibilidade
print(f"🛠️ Versões usadas:\n"
      f"TensorFlow: {tf.__version__}\n"
      f"Keras: {keras.__version__}\n"
      f"NumPy: {np.__version__}\n"
      f"Matplotlib: {matplotlib.__version__}\n")

# --- Carregamento e exploração inicial do dataset ---
from tensorflow.keras.datasets import fashion_mnist
(X_treinamento, y_treinamento), (X_teste, y_teste) = fashion_mnist.load_data()

# --- Visualização de um exemplo ---
# Lista de nomes correspondentes às classes de 0 a 9
nomes_classes = ['Camiseta/Top', 'Calça', 'Pulôver', 'Vestido', 'Casaco',
                 'Sandália', 'Camisa', 'Tênis', 'Bolsa', 'Bota']
i = 7 # índice da amostra a visualizar (modifique se quiser ver outra)
plt.imshow(X_treinamento[i], cmap='gray')  # exibe como imagem em tons de cinza
plt.title('Classe ' + nomes_classes[y_treinamento[i]]) # título com a classe
plt.axis('off')
plt.show()

# --- Pré-processamento dos dados ---
# Mostra dimensão antes da transformação
print(f"🔍 Antes da transformação – treino: {X_treinamento.shape}, teste: {X_teste.shape}")

# Ajustando forma para incluir canal único (1)
X_treinamento = X_treinamento.reshape(X_treinamento.shape[0], 28, 28, 1)
X_teste = X_teste.reshape(X_teste.shape[0], 28, 28, 1)

# Convertendo para float32 e normalizando valores para [0,1]
X_treinamento = X_treinamento.astype('float32') / 255
X_teste = X_teste.astype('float32') / 255

# Mostra dimensão após a transformação
print(f"✅ Depois da transformação – treino: {X_treinamento.shape}, teste: {X_teste.shape}\n")

# --- Configuração de Hiperparâmetros da Arquitetura ---
NUM_FILTERS  = 8           # Quantidade de filtros na camada Conv2D
KERNEL_SIZE  = (3, 3)      # Tamanho do kernel convolucional
POOL_SIZE    = (2, 2)      # Tamanho da região de pooling
DENSE_UNITS  = 32          # Número de neurônios nas camadas densas
DROPOUT_RATE = 0.1         # Taxa de dropout para camadas densas

# --- Definição e treinamento da CNN ---
from tensorflow.keras.models import Sequential
from tensorflow.keras.layers import InputLayer, Conv2D, BatchNormalization, MaxPooling2D, Flatten, Dense, Dropout
from tensorflow.keras.callbacks import EarlyStopping

rede = Sequential([ #rede Feedforward (direta)
    InputLayer(input_shape=(28, 28, 1)), # camada de entrada
    # Primeira camada convolucional: 32 filtros 3x3, ativação ReLU
    Conv2D(NUM_FILTERS, KERNEL_SIZE, activation='relu'),
    BatchNormalization(), # camada de normalização para acelerar convergência
    MaxPooling2D(pool_size=POOL_SIZE), # camada de pooling para reduzir dimensionalidade
    # Camada Flatten: transforma mapa de características em vetor
    Flatten(),
    # Camada densa (MLP) com Dropout para evitar overfitting
    Dense(DENSE_UNITS, activation='relu'),
    Dropout(DROPOUT_RATE),
    # Camada de saída: 10 neurônios, ativação softmax para classificação
    Dense(len(nomes_classes), activation='softmax')
])
# Exibe resumo da arquitetura e número de parâmetros
rede.summary()

"""# Como a Batch Normalization funciona:
![image.png](data:image/png;base64,)

![image.png](data:image/png;base64,)
"""

# --- Treinamento com validação e early stopping ---
from tensorflow.keras.callbacks import EarlyStopping

# --- Configuração de Hiperparâmetros de Treinamento ---
BATCH_SIZE        = 512         # Tamanho do lote para treinamento
EPOCHS            = 10          # Número de épocas para treino
PATIENCE          = 5           # Paciência para EarlyStopping
VALIDATION_SPLIT  = 0.2         # Fração dos dados usada para validação
OPTIMIZER         = 'sgd'      # Otimizador para treino

rede.compile(loss='sparse_categorical_crossentropy',
             optimizer=OPTIMIZER,
             metrics=['accuracy'])
#Configuração do Early Stopping
early_stopping = EarlyStopping(monitor='val_loss',
                               patience=PATIENCE, #máximo de "strikes"
                               restore_best_weights=True) #volta para a melhor configuração
treinamento = rede.fit(X_treinamento, y_treinamento,
                       batch_size=BATCH_SIZE, #tamanho do batch
                       epochs=EPOCHS, #máximo de épocas
                       validation_split=VALIDATION_SPLIT,  # separa dados para validação
                       callbacks=[early_stopping])

# --- Plots de métricas ---
fig, axes = plt.subplots(1, 2, figsize=(14, 5))

# Acurácia
axes[0].plot(treinamento.history['accuracy'], label='Treino')
axes[0].plot(treinamento.history['val_accuracy'], label='Validação')
axes[0].set_title('Acurácia durante o treinamento')
axes[0].set_xlabel('Época')
axes[0].set_ylabel('Accuracy')
axes[0].legend()

# Loss/Erro
axes[1].plot(treinamento.history['loss'], label='Treino')
axes[1].plot(treinamento.history['val_loss'], label='Validação')
axes[1].set_title('Erro durante o treinamento')
axes[1].set_xlabel('Época')
axes[1].set_ylabel('Loss/Erro')
axes[1].legend()

plt.tight_layout()
plt.show()

# --- Avaliação no conjunto de teste ---
resultado_teste = rede.evaluate(X_teste, y_teste)
print(f"🧪 Resultado no teste: Loss = {resultado_teste[0]:.4f}, Accuracy = {resultado_teste[1]:.4f}")

# --- Matriz de Confusão  ---
from sklearn.metrics import confusion_matrix

predicoes = rede.predict(X_teste)
y_pred = np.argmax(predicoes, axis=1)
cm = confusion_matrix(y_teste, y_pred)

fig, ax = plt.subplots(figsize=(8, 6))
im = ax.imshow(cm, interpolation='nearest', cmap=plt.cm.Blues)
ax.set_title('Matriz de Confusão')
fig.colorbar(im, ax=ax)
tick_marks = np.arange(len(nomes_classes))
ax.set_xticks(tick_marks)
ax.set_yticks(tick_marks)
ax.set_xticklabels([f"{i}: {nome}" for i, nome in enumerate(nomes_classes)], rotation=45)
ax.set_yticklabels([f"{i}: {nome}" for i, nome in enumerate(nomes_classes)])
ax.set_ylabel('Real')
ax.set_xlabel('Predito')
thresh = cm.max() / 2
for i in range(cm.shape[0]):
    for j in range(cm.shape[1]):
        ax.text(j, i, format(cm[i, j], 'd'),
                ha="center", va="center",
                color="white" if cm[i, j] > thresh else "black")

plt.tight_layout()
plt.show()

from sklearn.model_selection import StratifiedKFold
resultados = []
kfold = StratifiedKFold(n_splits=5,
                        shuffle=True,
                        random_state=42)
for i_treino, i_teste in kfold.split(X_treinamento, y_treinamento):
    rede_cv = Sequential([
        InputLayer(input_shape=(28, 28, 1)),
        Conv2D(NUM_FILTERS, KERNEL_SIZE, activation='relu'),
        BatchNormalization(),
        MaxPooling2D(pool_size=POOL_SIZE),
        Flatten(),
        Dense(DENSE_UNITS, activation='relu'),
        Dropout(DROPOUT_RATE),
        Dense(len(nomes_classes), activation='softmax')
    ])
    rede_cv.compile(
        loss='sparse_categorical_crossentropy',
        optimizer=OPTIMIZER,
        metrics=['accuracy']
    )
    rede_cv.fit(
        X_treinamento[i_treino], y_treinamento[i_treino],
        batch_size=BATCH_SIZE,
        epochs=6,
        validation_split=VALIDATION_SPLIT, callbacks=[early_stopping]
    )
    resultados.append(rede_cv.evaluate(X_treinamento[i_teste], y_treinamento[i_teste]))

resultados = np.array(resultados)
losses = resultados[:, 0]
accuracies = resultados[:, 1]
media_loss, std_loss = np.mean(losses), np.std(losses)
media_acc, std_acc   = np.mean(accuracies), np.std(accuracies)

print(f'📊 Média dos erros: {media_loss:.4f} ± {std_loss:.4f}')
print(f'📊 Média das acurácias: {media_acc:.4f} ± {std_acc:.4f}')